export const TWO_PI = Math.PI * 2;

/** Frequency ratio for a deviation in cents (100 cents = 1 ET semitone). */
export function centsToRatio(cents: number): number {
  return Math.pow(2, cents / 1200);
}

/** Deviation in cents for a frequency ratio (> 0). */
export function ratioToCents(ratio: number): number {
  return 1200 * Math.log2(ratio);
}

/** Cents deviation of `actualHz` relative to `targetHz`. */
export function hzToCents(actualHz: number, targetHz: number): number {
  return ratioToCents(actualHz / targetHz);
}

/** Absolute Hz offset corresponding to a cents deviation at `targetHz`. */
export function centsToHz(cents: number, targetHz: number): number {
  return targetHz * (centsToRatio(cents) - 1);
}

/** Wrap a phase to (-π, π], the shortest-path representation. */
export function wrapPhase(phi: number): number {
  let p = phi % TWO_PI;
  if (p > Math.PI) p -= TWO_PI;
  else if (p <= -Math.PI) p += TWO_PI;
  return p;
}

export function dbToLin(db: number): number {
  return Math.pow(10, db / 20);
}

export function linToDb(lin: number): number {
  return 20 * Math.log10(lin);
}
