import type { BandTarget, EngineParams } from "./types";

/**
 * Snapshot layout ("snapshot v1") — one Float32Array posted from the worklet
 * to the UI at ~94 Hz. Fixed layout so the buffer pool never reallocates.
 */
export const SNAP_SEQ = 0;
export const SNAP_TIME_SEC = 1;
export const SNAP_INPUT_RMS = 2;
export const SNAP_INPUT_PEAK = 3;
export const SNAP_FLAGS = 4;
export const SNAP_STRIKE_COUNT = 5;
export const SNAP_BAND_COUNT = 6;
export const SNAPSHOT_HEADER = 8;
export const SNAPSHOT_BAND_STRIDE = 8;

export const BAND_ID = 0;
export const BAND_PHASE = 1;
export const BAND_DPHIDT = 2;
export const BAND_AMPLITUDE = 3;
export const BAND_DELTA_CENTS = 4; // NaN when I/Q capture is invalid
export const BAND_DELTA_HZ = 5;
export const BAND_FLAGS = 6;

export const SNAP_FLAG_CLIPPING = 1;
export const SNAP_FLAG_FROZEN = 2;
export const SNAP_FLAG_HOLD = 4;
export const SNAP_FLAG_ATTACK_SKIP = 8;

export const BAND_FLAG_ACTIVE = 1;
export const BAND_FLAG_GATED = 2;
export const BAND_FLAG_HELD = 4;

export function snapshotLength(maxBands: number): number {
  return SNAPSHOT_HEADER + maxBands * SNAPSHOT_BAND_STRIDE;
}

/** Samples per raw-audio chunk forwarded to the analysis worker. */
export const AUDIO_CHUNK_SIZE = 2048;

/**
 * Should a band's strobe-derived (fine) cents reading be trusted for
 * display, given the FFT-derived coarse deviation for the same band?
 *
 * A partial farther off than the demodulator's read-rate alias limit folds
 * back into range and produces a stable, confident, WRONG fine reading (a
 * 60c-flat 2.3 kHz partial can read "+4.5c"). The fold survives every
 * amplitude gate, so the FFT coarse measurement is the discriminator: if it
 * exists and says the partial is far off — or flatly contradicts the fine
 * value — the coarse number must carry the display.
 */
export function isFineReadingTrusted(
  fineCents: number,
  coarseCents: number,
  opts?: { fineRangeCents?: number; agreementCents?: number },
): boolean {
  const fineRange = opts?.fineRangeCents ?? 30;
  const agreement = opts?.agreementCents ?? 15;
  if (!Number.isFinite(fineCents) || Math.abs(fineCents) > fineRange) {
    return false;
  }
  if (Number.isFinite(coarseCents)) {
    if (Math.abs(coarseCents) > fineRange) return false;
    if (Math.abs(coarseCents - fineCents) > agreement) return false;
  }
  return true;
}

/** Main thread → worklet. */
export type WorkletCommand =
  | { type: "configure"; bands: BandTarget[] }
  | { type: "retarget"; bands: BandTarget[]; resetFilters: boolean }
  | { type: "freeze"; on: boolean }
  | { type: "params"; params: Partial<EngineParams> }
  /** Return a consumed snapshot buffer to the worklet's pool. */
  | { type: "return"; buffer: ArrayBuffer }
  /** Return a consumed raw-audio buffer to the worklet's pool. */
  | { type: "return-audio"; buffer: ArrayBuffer }
  /**
   * Switch to external-PCM mode (native capture): the engine rebuilds at
   * the HARDWARE sample rate and mic input quanta are ignored from then
   * on. sampleRate 0 switches BACK to the context-driven input path. Must
   * be sent before configure/params so the fresh engine gets re-programmed
   * by the messages that follow (port order guarantees it).
   */
  | { type: "external"; sampleRate: number }
  /** External mono Float32 PCM chunk (buffer is transferred). */
  | { type: "pcm"; buffer: ArrayBuffer };

/**
 * Worklet → main thread. Snapshots are posted as raw ArrayBuffers
 * (transferred); structured events use tagged objects.
 */
export type WorkletEvent =
  | { type: "ready"; sampleRate: number }
  | { type: "strike"; atSample: number; peakLevel: number }
  /** Raw mono audio for the analysis worker (buffer is transferred). */
  | { type: "audio"; buffer: ArrayBuffer };
