import { TWO_PI } from "./math";

/**
 * Cascade of identical one-pole lowpass filters (y += a·(x − y) per stage).
 * Cutoff is the per-stage -3 dB point; the cascade's overall -3 dB point sits
 * somewhat below it, which is fine for band-selectivity purposes — what
 * matters is the ~6 dB/oct/stage rolloff rejecting neighboring partials.
 *
 * Allocation-free after construction; float64 state throughout.
 */
export class LpfCascade {
  private readonly stages: Float64Array;
  private a = 0;
  cutoffHz = 0;

  constructor(
    readonly sampleRate: number,
    cutoffHz: number,
    readonly numStages = 3,
  ) {
    this.stages = new Float64Array(numStages);
    this.setCutoff(cutoffHz);
  }

  setCutoff(cutoffHz: number): void {
    this.cutoffHz = cutoffHz;
    this.a = 1 - Math.exp((-TWO_PI * cutoffHz) / this.sampleRate);
  }

  reset(value = 0): void {
    this.stages.fill(value);
  }

  processSample(x: number): number {
    const s = this.stages;
    const a = this.a;
    let v = x;
    for (let k = 0; k < s.length; k++) {
      s[k]! += a * (v - s[k]!);
      v = s[k]!;
    }
    return v;
  }

  /** Last output without advancing state. */
  get value(): number {
    return this.stages[this.stages.length - 1]!;
  }
}
