import { BandDemodulator } from "./band-demodulator";
import { dbToLin } from "./math";
import {
  BAND_AMPLITUDE,
  BAND_DELTA_CENTS,
  BAND_DELTA_HZ,
  BAND_DPHIDT,
  BAND_FLAG_ACTIVE,
  BAND_FLAG_GATED,
  BAND_FLAG_HELD,
  BAND_FLAGS,
  BAND_ID,
  BAND_PHASE,
  SNAP_BAND_COUNT,
  SNAP_FLAG_ATTACK_SKIP,
  SNAP_FLAG_CLIPPING,
  SNAP_FLAG_FROZEN,
  SNAP_FLAG_HOLD,
  SNAP_FLAGS,
  SNAP_INPUT_PEAK,
  SNAP_INPUT_RMS,
  SNAP_SEQ,
  SNAP_STRIKE_COUNT,
  SNAP_TIME_SEC,
  SNAPSHOT_BAND_STRIDE,
  SNAPSHOT_HEADER,
} from "./protocol";
import { StrikeDetector } from "./strike-detector";
import {
  DEFAULT_ENGINE_PARAMS,
  type BandTarget,
  type EngineParams,
  type StrikeEvent,
} from "./types";

type EngineState = "idle" | "attackSkip" | "live" | "hold";

/** Bands whose baseband vector is below this are numerically meaningless. */
const VALID_AMPLITUDE = 1e-4;
/** Bands above this are considered ringing (drawn at full confidence). */
const ACTIVE_AMPLITUDE = 1e-3;
/** Stable-hold requires the level to have decayed at least this far below
 *  the strike peak — a sustained tone (not a struck note) never captures. */
const STABLE_DECAY_RATIO = 0.7;
/** A band anchors the stable verdict when it produced valid readings in at
 *  least this fraction of the window's reads. */
const STABLE_MIN_COVERAGE = 0.6;

/**
 * Top-level per-sample strobe engine: N band demodulators behind a
 * strike-aware gate. Runs in the AudioWorklet (or directly in tests/bench).
 *
 * State machine: strike → attackSkip (pitch glide, readouts gated) → live →
 * decay below strike peak + holdReleaseDb → hold (readouts frozen, strobe
 * still) → next strike releases.
 *
 * Hot path is allocation-free; snapshots are written into caller-provided
 * buffers (see protocol.ts for layout).
 */
export class StrobeEngine {
  private readonly bands: BandDemodulator[];
  private readonly targets: (BandTarget | null)[];
  private bandCount = 0;

  private readonly detector: StrikeDetector;
  private params: EngineParams = { ...DEFAULT_ENGINE_PARAMS };

  private state: EngineState = "idle";
  private frozen = false;
  private strikeCount = 0;
  private strikePeak = 0;
  private skipUntilSample = 0;
  private needsPrime = false;

  private samplesProcessed = 0;
  private lastReadSample = -1;
  private blockRms = 0;
  private blockPeak = 0;
  private seq = 0;

  // Stable-hold window accumulators (fixed-size, allocation-free hot path).
  private stableStartSample = -1;
  private stableReads = 0;
  private readonly stableMin: Float64Array;
  private readonly stableMax: Float64Array;
  private readonly stableCount: Int32Array;

  onStrike?: (e: StrikeEvent) => void;

  constructor(readonly sampleRate: number, readonly maxBands = 8) {
    this.bands = Array.from(
      { length: maxBands },
      () => new BandDemodulator({ sampleRate }),
    );
    this.targets = new Array<BandTarget | null>(maxBands).fill(null);
    this.detector = new StrikeDetector(sampleRate);
    this.stableMin = new Float64Array(maxBands);
    this.stableMax = new Float64Array(maxBands);
    this.stableCount = new Int32Array(maxBands);
  }

  get currentState(): EngineState {
    return this.state;
  }

  get currentBandCount(): number {
    return this.bandCount;
  }

  /** Full band reconfiguration: sets count/ids and resets all filter state. */
  configureBands(targets: BandTarget[]): void {
    if (targets.length > this.maxBands) {
      throw new RangeError(
        `StrobeEngine: ${targets.length} bands exceeds maxBands=${this.maxBands}`,
      );
    }
    this.bandCount = targets.length;
    for (let k = 0; k < this.maxBands; k++) {
      const t = targets[k] ?? null;
      this.targets[k] = t;
      if (t) {
        this.bands[k]!.setTarget(t.freqHz, {
          resetFilters: true,
          lpfCutoffHz: t.lpfCutoffHz,
        });
      }
    }
    this.needsPrime = true;
    this.stableStartSample = -1;
    this.releaseHold();
  }

  /**
   * Update frequencies of the existing band set (matched by id; unmatched
   * targets are ignored). resetFilters=true on note changes kills the stale
   * baseband vector so the old note doesn't read as a deviation of the new.
   */
  retarget(targets: BandTarget[], resetFilters: boolean): void {
    for (const t of targets) {
      for (let k = 0; k < this.bandCount; k++) {
        if (this.targets[k]?.id === t.id) {
          this.targets[k] = t;
          this.bands[k]!.setTarget(t.freqHz, {
            resetFilters,
            lpfCutoffHz: t.lpfCutoffHz,
          });
          break;
        }
      }
    }
    if (resetFilters) {
      this.needsPrime = true;
      this.stableStartSample = -1;
      this.releaseHold();
    }
  }

  setParams(p: Partial<EngineParams>): void {
    this.params = { ...this.params, ...p };
    if (this.params.holdEnabled === false && this.state === "hold") {
      this.releaseHold();
      this.needsPrime = true;
    }
  }

  setFrozen(on: boolean): void {
    // Re-baseline phase tracking on unfreeze — otherwise the first read
    // spans the whole frozen gap and aliases into a bogus dPhiDt. The
    // stability window predates the freeze — restart it too.
    if (this.frozen && !on) {
      this.needsPrime = true;
      this.stableStartSample = -1;
    }
    this.frozen = on;
  }

  /**
   * Hold freezes readouts on a decayed note; a band-set change or disabling
   * hold must resume live readouts — the frozen values belong to the OLD
   * targets and must not be re-attributed to new ones. strikePeak resets so
   * hold can't immediately re-engage against a stale peak.
   */
  private releaseHold(): void {
    if (this.state === "hold") {
      this.state = "idle";
      this.strikePeak = 0;
    }
  }

  processBlock(input: Float32Array): void {
    // Input level metering for the LED.
    let sumSq = 0;
    let peak = 0;
    for (let n = 0; n < input.length; n++) {
      const x = input[n]!;
      sumSq += x * x;
      const a = Math.abs(x);
      if (a > peak) peak = a;
    }
    this.blockRms = Math.sqrt(sumSq / input.length);
    this.blockPeak = peak;

    const strike = this.detector.processBlock(input, this.samplesProcessed);
    if (strike) {
      this.strikeCount++;
      this.strikePeak = strike.peakLevel;
      this.state = "attackSkip";
      this.skipUntilSample =
        strike.atSample +
        Math.round((this.params.attackSkipMs / 1000) * this.sampleRate);
      this.stableStartSample = -1; // new note — restart the stability window
      this.onStrike?.(strike);
    }

    for (let k = 0; k < this.bandCount; k++) {
      this.bands[k]!.processBlock(input);
    }
    this.samplesProcessed += input.length;

    // A real hand-strike attack rises over 5–10 ms, so the true peak lands
    // after the trigger block; keep raising strikePeak through the skip
    // window so the hold threshold anchors to the actual peak.
    if (this.state === "attackSkip" && this.blockPeak > this.strikePeak) {
      this.strikePeak = this.blockPeak;
    }

    if (this.state === "attackSkip" && this.samplesProcessed >= this.skipUntilSample) {
      this.state = "live";
      this.needsPrime = true;
    }
    if (
      this.state === "live" &&
      this.params.holdEnabled &&
      this.strikePeak > 0 &&
      this.detector.fastLevel <
        this.strikePeak * dbToLin(this.params.holdReleaseDb)
    ) {
      this.state = "hold";
    }
  }

  /**
   * Advance band readouts per the state machine. Call at message rate before
   * fillSnapshot. Gated (attack-skip), held, and frozen states intentionally
   * leave the previous readings in place — the strobe freezes rather than
   * showing the glide or noise.
   */
  readFrames(): void {
    const updating =
      !this.frozen && (this.state === "live" || this.state === "idle");
    if (!updating) return;
    // Any read gap (snapshot-pool exhaustion, main-thread stall) longer than
    // a few snapshot intervals would alias the phase delta — re-prime.
    const gap = this.samplesProcessed - this.lastReadSample;
    if (this.lastReadSample >= 0 && gap > 4 * 512) this.needsPrime = true;
    this.lastReadSample = this.samplesProcessed;
    if (this.needsPrime) {
      // First read after a gap: re-baseline phase tracking so the stale
      // phase delta across the gap doesn't alias into a bogus dPhiDt.
      // (The stability window deliberately survives gap re-primes — a
      // main-thread stall doesn't change the note; real discontinuities
      // reset it explicitly at their source.)
      for (let k = 0; k < this.bandCount; k++) this.bands[k]!.primeFrame();
      this.needsPrime = false;
      return;
    }
    for (let k = 0; k < this.bandCount; k++) this.bands[k]!.readFrame();

    if (
      this.params.stableHoldEnabled &&
      this.params.holdEnabled &&
      this.state === "live"
    ) {
      this.trackStability();
    }
  }

  /**
   * Auto-capture ("stable hold"): during post-strike live reading, watch
   * consecutive windows of stableWindowMs. If every ringing band's deltaCents
   * stays within stableSpreadCents while the level clearly decays below the
   * strike peak, the readings ARE the note — enter hold now instead of
   * waiting for the full decay, so short notes stay readable. A wobbling
   * (beating) band exceeds the spread and keeps its live readout; a
   * sustained tone never decays and never captures. Next strike releases.
   */
  private trackStability(): void {
    if (this.stableStartSample < 0) {
      this.stableStartSample = this.samplesProcessed;
      this.stableReads = 0;
      for (let k = 0; k < this.bandCount; k++) {
        this.stableMin[k] = Infinity;
        this.stableMax[k] = -Infinity;
        this.stableCount[k] = 0;
      }
      return;
    }
    this.stableReads++;
    for (let k = 0; k < this.bandCount; k++) {
      const d = this.bands[k]!;
      const c = d.deltaCents;
      if (d.amplitude >= ACTIVE_AMPLITUDE && Number.isFinite(c)) {
        if (c < this.stableMin[k]!) this.stableMin[k] = c;
        if (c > this.stableMax[k]!) this.stableMax[k] = c;
        this.stableCount[k]!++;
      }
    }
    const windowSamples = Math.round(
      (this.params.stableWindowMs / 1000) * this.sampleRate,
    );
    if (this.samplesProcessed - this.stableStartSample < windowSamples) return;

    const decayed =
      this.strikePeak > 0 &&
      this.detector.fastLevel < this.strikePeak * STABLE_DECAY_RATIO;
    const minCount = Math.max(
      4,
      Math.ceil(this.stableReads * STABLE_MIN_COVERAGE),
    );
    let anchored = 0;
    let stable = true;
    for (let k = 0; k < this.bandCount; k++) {
      if (this.stableCount[k]! === 0) continue;
      // A partial that died away mid-window no longer rings — its historic
      // jitter must not block capturing the partials that still do.
      if (this.bands[k]!.amplitude < ACTIVE_AMPLITUDE) continue;
      if (
        this.stableMax[k]! - this.stableMin[k]! >
        this.params.stableSpreadCents
      ) {
        stable = false;
        break;
      }
      if (this.stableCount[k]! >= minCount) anchored++;
    }
    if (decayed && stable && anchored > 0) {
      this.state = "hold";
    } else {
      this.stableStartSample = -1; // judge the next window
    }
  }

  fillSnapshot(buf: Float32Array): void {
    buf[SNAP_SEQ] = this.seq++;
    buf[SNAP_TIME_SEC] = this.samplesProcessed / this.sampleRate;
    buf[SNAP_INPUT_RMS] = this.blockRms;
    buf[SNAP_INPUT_PEAK] = this.blockPeak;
    let flags = 0;
    if (this.blockPeak > 0.99) flags |= SNAP_FLAG_CLIPPING;
    if (this.frozen) flags |= SNAP_FLAG_FROZEN;
    if (this.state === "hold") flags |= SNAP_FLAG_HOLD;
    if (this.state === "attackSkip") flags |= SNAP_FLAG_ATTACK_SKIP;
    buf[SNAP_FLAGS] = flags;
    buf[SNAP_STRIKE_COUNT] = this.strikeCount;
    buf[SNAP_BAND_COUNT] = this.bandCount;
    buf[SNAPSHOT_HEADER - 1] = 0;

    for (let k = 0; k < this.bandCount; k++) {
      const demod = this.bands[k]!;
      const base = SNAPSHOT_HEADER + k * SNAPSHOT_BAND_STRIDE;
      buf[base + BAND_ID] = this.targets[k]?.id ?? -1;
      buf[base + BAND_PHASE] = demod.phase;
      buf[base + BAND_DPHIDT] = demod.dPhiDt;
      buf[base + BAND_AMPLITUDE] = demod.amplitude;
      buf[base + BAND_DELTA_CENTS] =
        demod.amplitude >= VALID_AMPLITUDE ? demod.deltaCents : NaN;
      buf[base + BAND_DELTA_HZ] = demod.deltaFHz;
      let bandFlags = 0;
      if (demod.amplitude >= ACTIVE_AMPLITUDE) bandFlags |= BAND_FLAG_ACTIVE;
      if (this.state === "attackSkip") bandFlags |= BAND_FLAG_GATED;
      if (this.state === "hold") bandFlags |= BAND_FLAG_HELD;
      buf[base + BAND_FLAGS] = bandFlags;
      buf[base + 7] = 0;
    }
  }
}
