import { linToDb } from "./math";
import type { StrikeEvent } from "./types";

export interface StrikeDetectorOptions {
  attackMs?: number;
  releaseMs?: number;
  slowMs?: number;
  /** Slow-tracker fall time — fast enough that a damped note re-arms soon. */
  slowDownMs?: number;
  triggerRatioDb?: number;
  refractoryMs?: number;
  /** Absolute level floor for triggering, dBFS. */
  floorDb?: number;
}

/**
 * Edge-triggered strike detector. A fast envelope (1 ms attack / 50 ms
 * release on |x|) is compared against a slow tracker that smooths the fast
 * envelope itself (500 ms) — for stationary signal or noise the ratio hovers
 * near 1, while a hammer strike steps the fast envelope 20–40 dB in
 * milliseconds. Triggering is armed/latched: after a strike the ratio must
 * fall back within half the threshold (in dB) before a new strike can fire,
 * so a ringing, slowly-decaying note cannot re-trigger. A refractory period
 * additionally suppresses double-hits, and an absolute floor ignores silence.
 */
export class StrikeDetector {
  private readonly aFast: number;
  private readonly rFast: number;
  private readonly aSlow: number;
  private readonly dSlow: number;
  private readonly triggerRatioLin: number;
  private readonly rearmRatioLin: number;
  private readonly floorLin: number;
  private readonly refractorySamples: number;

  private fast = 0;
  private slow: number;
  private armed = true;
  private samplesSinceStrike: number;

  constructor(readonly sampleRate: number, opts?: StrikeDetectorOptions) {
    const attackMs = opts?.attackMs ?? 1;
    const releaseMs = opts?.releaseMs ?? 50;
    const slowMs = opts?.slowMs ?? 500;
    const slowDownMs = opts?.slowDownMs ?? 100;
    const triggerRatioDb = opts?.triggerRatioDb ?? 12;
    this.aFast = 1 - Math.exp(-1000 / (attackMs * sampleRate));
    this.rFast = 1 - Math.exp(-1000 / (releaseMs * sampleRate));
    this.aSlow = 1 - Math.exp(-1000 / (slowMs * sampleRate));
    this.dSlow = 1 - Math.exp(-1000 / (slowDownMs * sampleRate));
    this.triggerRatioLin = Math.pow(10, triggerRatioDb / 20);
    this.rearmRatioLin = Math.pow(10, triggerRatioDb / 40);
    this.floorLin = Math.pow(10, (opts?.floorDb ?? -50) / 20);
    this.refractorySamples = Math.round(
      ((opts?.refractoryMs ?? 100) / 1000) * sampleRate,
    );
    this.samplesSinceStrike = this.refractorySamples;
    // Start the slow tracker well above the floor so app startup into
    // ambient noise doesn't read as a strike; it converges within ~1 s.
    this.slow = this.floorLin * 10;
  }

  /** Fast envelope level, linear — the "current loudness" other logic reads. */
  get fastLevel(): number {
    return this.fast;
  }

  /** Slow tracker in dBFS — a serviceable ambient-level estimate. */
  get noiseFloorDb(): number {
    return this.slow > 0 ? linToDb(this.slow) : -120;
  }

  /**
   * Returns the first strike detected within this block, or null. Envelope
   * state advances across the whole block regardless.
   */
  processBlock(
    input: Float32Array,
    blockStartSample: number,
  ): StrikeEvent | null {
    let event: StrikeEvent | null = null;
    for (let n = 0; n < input.length; n++) {
      const x = Math.abs(input[n]!);
      this.fast += (x > this.fast ? this.aFast : this.rFast) * (x - this.fast);
      // Asymmetric slow tracker: rises slowly (a strike is a step above it)
      // but falls fast, so a hand-damped note re-arms the detector quickly
      // and a softer restrike right after a loud one is not missed.
      this.slow +=
        (this.fast > this.slow ? this.aSlow : this.dSlow) *
        (this.fast - this.slow);
      this.samplesSinceStrike++;

      const ratioHigh = this.fast > this.slow * this.triggerRatioLin;
      if (!this.armed) {
        if (this.fast < this.slow * this.rearmRatioLin) this.armed = true;
      } else if (
        event === null &&
        ratioHigh &&
        this.fast > this.floorLin &&
        this.samplesSinceStrike >= this.refractorySamples
      ) {
        event = { atSample: blockStartSample + n, peakLevel: this.fast };
        this.samplesSinceStrike = 0;
        this.armed = false;
      }
    }
    if (event) {
      // The block max is a better strike-peak estimate than the envelope
      // value at the trigger instant.
      let peak = event.peakLevel;
      for (let n = 0; n < input.length; n++) {
        const a = Math.abs(input[n]!);
        if (a > peak) peak = a;
      }
      event.peakLevel = peak;
    }
    return event;
  }
}
