/** One strobe band's tuning target. Musical mapping happens UI-side. */
export interface BandTarget {
  /** Stable identity used to match bands across retargets. */
  id: number;
  freqHz: number;
  /** Override the default cutoff heuristic (used by auto-widen). */
  lpfCutoffHz?: number;
}

export interface EngineParams {
  /** Skip this long after a strike — the attack pitch glide (ms). */
  attackSkipMs: number;
  /** Freeze readouts when the note has decayed away instead of showing noise. */
  holdEnabled: boolean;
  /** Hold engages when level falls this far below the strike peak (dB, negative). */
  holdReleaseDb: number;
  /** Auto-capture: enter hold as soon as a struck note's readings settle
   *  (see stableWindowMs/stableSpreadCents) instead of waiting for the full
   *  decay. Short notes become readable; the next strike releases as usual. */
  stableHoldEnabled: boolean;
  /** Readings must hold still this long to count as settled (ms). */
  stableWindowMs: number;
  /** …staying within this total spread (cents). Real adjacent-note wobble
   *  (2–40¢ p-p) exceeds this, so a beating note keeps its live readout. */
  stableSpreadCents: number;
}

export const DEFAULT_ENGINE_PARAMS: EngineParams = {
  attackSkipMs: 120,
  holdEnabled: true,
  holdReleaseDb: -40,
  stableHoldEnabled: false,
  stableWindowMs: 500,
  stableSpreadCents: 2.5,
};

export interface StrikeEvent {
  atSample: number;
  /** Peak |sample| around the strike onset, linear. */
  peakLevel: number;
}
